import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import {
  Table,
  TableHead,
  TableBody,
  TableCell,
  TableContainer,
  TableRow,
  Paper,
} from "@mui/material";
import { useEffect } from "react";
import { initializeUsers } from "../reducers/userReducer";
import { initializeBlogs } from "../reducers/blogReducer";

const Users = () => {
  const dispatch = useDispatch();
  useEffect(() => {
    dispatch(initializeUsers());
  }, [dispatch]);
  const users = useSelector((state) => state.users);
  useEffect(() => {
    dispatch(initializeBlogs());
  }, [dispatch]);

  const blogs = useSelector((state) => state.blogs);
  const currUser = useSelector((state) => state.login);
  //console.log(currUser);
  const currUsername = currUser?.username;
  /*   console.log(currUsername);
  console.log(blogs) */
  const usersBlogs = blogs?.find((b) => b.user.username === currUsername);
  const currUserId = usersBlogs?.user?.id;
  /*   console.log(currUserId); */
  let currUsersBlogs = blogs?.filter((b) => b.user.username === currUsername);
  /*   console.log(currUsersBlogs); */
  let newBlog = blogs?.filter((b) => b.user === currUserId);
  currUsersBlogs = currUsersBlogs.concat(newBlog);
  /*   console.log(currUsersBlogs); */
  const currUserBlogsLength = currUsersBlogs?.length;
  /*  console.log(currUserBlogsLength);
  console.log(newBlog);
  console.log(currUserId);
  console.log(blogs.user); */

  return (
    <div>
      <h2>Users</h2>
      <TableContainer sx={{ minWidth: 250 }} component={Paper}>
        <Table size="small">
          <TableHead>
            <TableRow>
              <TableCell className="table-header">
                <strong>Name</strong>
              </TableCell>
              <TableCell align="right" className="table-header">
                <strong>blogs created</strong>
              </TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {users.map((user) => (
              <TableRow key={user.id}>
                <TableCell>
                  <Link to={`/users/${user.id}`}>{user.username}</Link>
                </TableCell>
                <TableCell align="right">
                  {currUsername &&
                  currUserBlogsLength &&
                  currUsername === user.username
                    ? currUserBlogsLength
                    : user.blogs.length}
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </TableContainer>
    </div>
  );
};

export default Users;
